    "practiceType": "\u2014",
    "practiceCount": 0,
    "threshold": 70,
    "isSynthesis": false,
    "generatesReading": false,
    "approved": true,
    "rule": "\u0418\u0432\u0440\u0438\u0442\u0441\u043A\u0438\u0435 \u0441\u043B\u043E\u0432\u0430 \u0441\u0442\u0440\u043E\u044F\u0442\u0441\u044F \u043A\u0430\u043A \u043A\u043E\u043D\u0441\u0442\u0440\u0443\u043A\u0442\u043E\u0440: \u041A\u041E\u0420\u0415\u041D\u042C + \u0428\u0410\u0411\u041B\u041E\u041D = \u0441\u043B\u043E\u0432\u043E. \u041A\u043E\u0440\u0435\u043D\u044C \u2014 \u044D\u0442\u043E 3 \u0431\u0443\u043A\u0432\u044B, \u043D\u0435\u0441\u0443\u0449\u0438\u0435 \u0441\u043C\u044B\u0441\u043B. \u0428\u0430\u0431\u043B\u043E\u043D (\u0431\u0438\u043D\u044C\u044F\u043D) \u2014 \u044D\u0442\u043E \u0444\u043E\u0440\u043C\u0430, \u0432 \u043A\u043E\u0442\u043E\u0440\u0443\u044E \u043A\u043E\u0440\u0435\u043D\u044C \xAB\u0432\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442\u0441\u044F\xBB. \u0422\u0430\u043C\u0430\u0440 \u0443\u0434\u0438\u0432\u043B\u044F\u0435\u0442\u0441\u044F: \u043A\u043E\u0440\u0435\u043D\u044C \u05D4-\u05DC-\u05DB (\u0438\u0434\u0435\u044F \xAB\u0445\u043E\u0434\u0438\u0442\u044C\xBB) + \u0448\u0430\u0431\u043B\u043E\u043D \u043F\u0430\u0410\u043B\u044C = \u05D4\u05D5\u05B9\u05DC\u05B5\u05DA\u05B0 (\u0438\u0434\u0451\u0442). \u041A\u043E\u0440\u0435\u043D\u044C \u05D0-\u05DB-\u05DC (\u0438\u0434\u0435\u044F \xAB\u0435\u0434\u044B\xBB) + \u0442\u043E\u0442 \u0436\u0435 \u0448\u0430\u0431\u043B\u043E\u043D = \u05D0\u05D5\u05B9\u05DB\u05B5\u05DC (\u0435\u0441\u0442). \u041A\u043E\u0440\u0435\u043D\u044C \u05D0-\u05D4-\u05D1 + \u043F\u0430\u0410\u043B\u044C = \u05D0\u05D5\u05B9\u05D4\u05B5\u05D1 (\u043B\u044E\u0431\u0438\u0442). \u0421\u043C\u043E\u0442\u0440\u0438: \u0443 \u0432\u0441\u0435\u0445 \u043E\u0434\u0438\u043D \u0440\u0438\u0441\u0443\u043D\u043E\u043A \u043E\u0433\u043B\u0430\u0441\u043E\u0432\u043E\u043A \u2014 \xAB\u043E-\u044D\xBB (\u25CC\u05D5\u05B9\u25CC\u05B5\u25CC). \u0422\u044B \u0443\u0436\u0435 \u0437\u043D\u0430\u0435\u0448\u044C \u044D\u0442\u0438 \u0441\u043B\u043E\u0432\u0430 \u0438\u0437 \u0441\u043B\u043E\u0432\u0430\u0440\u044F \u2014 \u0442\u0435\u043F\u0435\u0440\u044C \u0442\u044B \u0432\u0438\u0434\u0438\u0448\u044C, \u041A\u0410\u041A \u043E\u043D\u0438 \u0443\u0441\u0442\u0440\u043E\u0435\u043D\u044B! \u042D\u0442\u043E \u043F\u0435\u0440\u0432\u044B\u0439 \u0438 \u0433\u043B\u0430\u0432\u043D\u044B\u0439 \u0431\u0438\u043D\u044C\u044F\u043D \u2014 \u043F\u0430\u0410\u043B\u044C. \u0422\u0435\u0441\u0442 \u043D\u0435 \u043D\u0443\u0436\u0435\u043D: \u043F\u0440\u043E\u0441\u0442\u043E \u043F\u043E\u0439\u043C\u0438 \u0438\u0434\u0435\u044E \u043A\u043E\u043D\u0441\u0442\u0440\u0443\u043A\u0442\u043E\u0440\u0430.",
